INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='青山镇'),'采药童子','药铺缺人手去青云山外门采集聚灵草。老板抠门报酬刚好够路费——但新手积累经验的好机会。',5,jsonb_build_array(jsonb_build_object('type','rare_item','name','聚灵草','weight',100,'min_count',1,'max_count',3)),1,100),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'灵石回收','镇商行回收散落灵石——说白了就是去各摊位捡别人落的灵石。',6,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',100,'min_amount',5,'max_amount',15)),1,100),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'镇志抄写','镇长编纂《青山镇千年志》缺人手抄写。报酬不高但附带免费住宿一日。',12,jsonb_build_array(jsonb_build_object('type','rare_item','name','聚灵草种子','weight',60,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',3,'max_amount',8)),1,100),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'茶铺帮工','茶铺老张崴了脚需要帮工三天。看你是修仙的给你几味药材当跑腿费。',15,jsonb_build_array(jsonb_build_object('type','rare_item','name','灵茶叶','weight',70,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',2,'max_amount',5)),1,100),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'石碑拓印','镇口天道酬勤石碑被渡劫失败散修劈成两半——拓印残碑上的功法文字。',18,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',8,'max_amount',20),jsonb_build_object('type','rare_item','name','凝气花','weight',50,'min_count',1,'max_count',2)),2,100),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'引气辅导','青山学院需修士辅导新弟子引气入体——耐心比修为重要。',20,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',10,'max_amount',25),jsonb_build_object('type','rare_item','name','培元丹','weight',40,'min_count',1,'max_count',2)),1,100),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'药田除虫','聚灵草田遭虫害——用火球术灭虫但别烧了田。上次有人把三亩田烧成黑炭赔了三年灵石。',10,jsonb_build_array(jsonb_build_object('type','rare_item','name','聚灵草','weight',80,'min_count',2,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',20,'min_amount',3,'max_amount',8)),1,100),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'送信外门','镇长有信需送到青云山外门长老——山路偶有妖兽。',10,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',5,'max_amount',12),jsonb_build_object('type','rare_item','name','凝气丹','weight',40,'min_count',1,'max_count',1)),1,90),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'庙会筹办','庙会将至需布置场地。据说和尚会送辟邪符——管不管用看缘分。',10,jsonb_build_array(jsonb_build_object('type','equipment','name','桃木符','weight',100,'template_id',(SELECT id FROM xt_equipment_template WHERE name='桃木符'))),1,100),
((SELECT id FROM xt_map_node WHERE name='青山镇'),'矿渣筛选','废弃灵石矿脉剩下的矿渣——筛一筛能凑几块灵石。',8,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',80,'min_amount',5,'max_amount',15),jsonb_build_object('type','rare_item','name','聚灵草','weight',20,'min_count',1,'max_count',2)),1,100);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'坊市跑腿','散修需帮忙跑腿送东西——能混脸熟说不定遇到便宜货。',8,jsonb_build_array(jsonb_build_object('type','rare_item','name','凝气丹','weight',60,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',3,'max_amount',8)),3,80),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'摊位看管','卖假古董的散修内急——帮看摊半炷香。有人来问价你赚了五块灵石抽成。',5,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',100,'min_amount',3,'max_amount',8)),1,80),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'灵石兑换','坊市兑换处排长龙——帮新来的绕道后门抽成一半。',6,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',100,'min_amount',5,'max_amount',15)),1,80),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'法器鉴定','有人拿法器来鉴定——帮鉴定师搬旧货晒晒蹭几块灵石。',12,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',5,'max_amount',12),jsonb_build_object('type','rare_item','name','火灵石','weight',50,'min_count',1,'max_count',2)),2,80),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'丹铺盘点','坊市最大丹铺季度盘点——帮忙清点库存。',20,jsonb_build_array(jsonb_build_object('type','rare_item','name','培元丹','weight',50,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',5,'max_amount',15)),1,80),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'散修传单','丹铺开分店需人派传单——一人一百张发完为止。',10,jsonb_build_array(jsonb_build_object('type','rare_item','name','培元丹','weight',100,'min_count',1,'max_count',3)),1,80),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'药材代购','有散修要去枯骨林采药但先要买够回春丹——帮他跑腿。',8,jsonb_build_array(jsonb_build_object('type','rare_item','name','回春丹','weight',100,'min_count',1,'max_count',3)),5,80),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'夜市灯会','坊市年度灵石灯会——帮挂灯笼后可免费抽奖——最低也是培元丹。',18,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',5,'max_amount',20),jsonb_build_object('type','rare_item','name','培元丹','weight',40,'min_count',1,'max_count',3),jsonb_build_object('type','rare_item','name','凝气丹','weight',20,'min_count',1,'max_count',1)),1,80),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'货郎护卫','往来青山镇的货郎怕被抢需护卫——货比人值钱这是行规。',20,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',8,'max_amount',20),jsonb_build_object('type','rare_item','name','筑基丹','weight',50,'min_count',1,'max_count',1)),5,70),
((SELECT id FROM xt_map_node WHERE name='落霞坊市'),'地摊砍价','两个散修为一块龙鳞吵了三天——需第三方仲裁。',15,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',5,'max_amount',20),jsonb_build_object('type','rare_item','name','筑基丹','weight',40,'min_count',1,'max_count',1)),3,80);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='天阙城'),'城门守备','守卫长需修士协助维护秩序——不用打打杀杀就是站一天腰有点疼。',30,jsonb_build_array(jsonb_build_object('type','rare_item','name','大还丹','weight',50,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',20,'max_amount',50)),30,40),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'星辰铁押运','从铸剑山押运星辰铁——路上别弄丢一块。',45,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',30,'max_amount',80),jsonb_build_object('type','rare_item','name','星辰砂','weight',60,'min_count',1,'max_count',3)),30,40),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'城中巡逻','内城巡逻——抓小偷抓骗子抓在城门口打太极的散修。',25,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',15,'max_amount',40),jsonb_build_object('type','rare_item','name','破障丹','weight',50,'min_count',1,'max_count',1)),30,35),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'地下坊市调查','刑部悬赏调查员调查地下坊市倒卖禁物——建议装成买家。',60,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',30,'max_amount',100),jsonb_build_object('type','rare_item','name','大还丹','weight',30,'min_count',1,'max_count',3),jsonb_build_object('type','rare_item','name','破障丹','weight',30,'min_count',1,'max_count',2)),35,30),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'炼丹师公会考核','炼丹师公会年度考核拉人充场子——只管拍手鼓掌就行。',30,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',15,'max_amount',30),jsonb_build_object('type','rare_item','name','筑基丹','weight',50,'min_count',1,'max_count',3)),30,35),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'城墙修补','城墙被雷劫劈了个缺口——需修士用体术搬运石料砌墙。',40,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',25,'max_amount',60),jsonb_build_object('type','equipment','name','聚灵玉佩','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='聚灵玉佩'))),35,30),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'铸剑委托','某高官委托铸剑山工匠打造法器——需人代为监督。',50,jsonb_build_array(jsonb_build_object('type','equipment','name','游龙刀','weight',100,'template_id',(SELECT id FROM xt_equipment_template WHERE name='游龙刀'))),30,30),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'大阵检查','护城大阵每年例行检查——需站桩填阵眼。',45,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',30,'max_amount',80),jsonb_build_object('type','rare_item','name','筑基丹','weight',30,'min_count',1,'max_count',3),jsonb_build_object('type','rare_item','name','破境丹','weight',20,'min_count',1,'max_count',1)),35,30),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'妖兽标本','博物阁急需妖兽标本——活的不要——妖兽在城里放出来没处关门。',35,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',20,'max_amount',50),jsonb_build_object('type','rare_item','name','舍利子','weight',30,'min_count',1,'max_count',2),jsonb_build_object('type','rare_item','name','龙鳞','weight',30,'min_count',1,'max_count',2)),32,35),
((SELECT id FROM xt_map_node WHERE name='天阙城'),'代购跑腿','青龙街代购——帮修士买他们懒得排长队的丹药。',25,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',10,'max_amount',40),jsonb_build_object('type','rare_item','name','培元丹','weight',40,'min_count',1,'max_count',3)),30,35);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'锻铁学徒','铁匠永远缺人——帮拉风箱搬铁块在他骂你时保持微笑。教的都是错的。',10,jsonb_build_array(jsonb_build_object('type','rare_item','name','玄铁','weight',60,'min_count',1,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',3,'max_amount',10)),15,70),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'火炉添煤','火灵石煤需人添进锻炉——煤灰飘满脸但冬天免费取暖。',15,jsonb_build_array(jsonb_build_object('type','rare_item','name','火灵石','weight',60,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',5,'max_amount',12)),15,70),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'淬火秘方看守','三大打铁世家有家传淬火秘方——需看守不让别家子弟偷看。',20,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',10,'max_amount',30),jsonb_build_object('type','rare_item','name','玄铁','weight',50,'min_count',1,'max_count',5)),15,70),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'法器维修中介','散修法器坏了需要急修——帮他去铁匠那边催并抽成。',12,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',100,'min_amount',8,'max_amount',20)),15,70),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'矿石鉴定','坊市送来一批未知矿石需鉴定——可能是九天息壤也可能只是石头。',25,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',10,'max_amount',30),jsonb_build_object('type','rare_item','name','万年寒铁','weight',50,'min_count',1,'max_count',3)),15,60),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'废剑回收','年度废剑回收日——把去年打坏的剑器分类回炉。',30,jsonb_build_array(jsonb_build_object('type','equipment','name','破风刀','weight',40,'template_id',(SELECT id FROM xt_equipment_template WHERE name='破风刀')),jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',8,'max_amount',25)),15,60),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'矿脉勘探','外围发现新矿脉迹象需修士勘探——梦想挖到九天息壤。',45,jsonb_build_array(jsonb_build_object('type','rare_item','name','玄铁','weight',50,'min_count',3,'max_count',10),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',10,'max_amount',30),jsonb_build_object('type','rare_item','name','万年寒铁','weight',20,'min_count',1,'max_count',2)),15,55),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'打铁大赛记分员','年度打铁大赛——记分员需数清每锤打击力。规则一：别让铁匠发现你记错了。',18,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',70,'min_amount',10,'max_amount',25),jsonb_build_object('type','equipment','name','碎星锤','weight',30,'template_id',(SELECT id FROM xt_equipment_template WHERE name='碎星锤'))),15,60),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'煤山清理','堆积一年煤渣需清理——挖通被堵小路。有时捡到炼废的法器碎片。',22,jsonb_build_array(jsonb_build_object('type','rare_item','name','火灵石','weight',80,'min_count',2,'max_count',8),jsonb_build_object('type','spirit_stones','name','灵石','weight',20,'min_amount',5,'max_amount',15)),15,60),
((SELECT id FROM xt_map_node WHERE name='铸剑山'),'铁匠传信','三个打铁世家互不来往——需信使在之间传话。别被火球术误伤就是稳赚。',10,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',100,'min_amount',5,'max_amount',15)),15,70);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'采药大典','年度盛事——一炷香内尽可能多采药但不能踩谷主灵植。',20,jsonb_build_array(jsonb_build_object('type','rare_item','name','聚灵草种子','weight',50,'min_count',1,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',10,'max_amount',30)),25,60),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'药田浇水','三百亩药田每天浇水——木系功法可温和浇水不用桶。',25,jsonb_build_array(jsonb_build_object('type','rare_item','name','朱果','weight',60,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',8,'max_amount',20)),25,60),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'魔藤驯养','谷口噬心魔藤是谷主守护兽——需人定期喂肉且别让它缠上自己。',30,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',15,'max_amount',40),jsonb_build_object('type','rare_item','name','火灵芝','weight',50,'min_count',1,'max_count',3)),25,55),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'药方对账','谷主编千年药方大全需人帮忙对账——枯燥但有意外收获。',35,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',15,'max_amount',30),jsonb_build_object('type','rare_item','name','回春丹','weight',50,'min_count',1,'max_count',3)),25,55),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'灵芝守护','两千年灵芝即将出土——需人日夜看守。谷主承诺出土后分成。',60,jsonb_build_array(jsonb_build_object('type','rare_item','name','千年灵芝','weight',60,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',20,'max_amount',50)),25,50),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'炼丹助教','三日炼丹速成班需助教看炉子。学员问题：火大了咋办？炸炉了咋办？着火了？',45,jsonb_build_array(jsonb_build_object('type','rare_item','name','回春丹','weight',50,'min_count',1,'max_count',3),jsonb_build_object('type','rare_item','name','筑基丹','weight',50,'min_count',1,'max_count',2)),25,55),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'药材分类入库','秋收药材大丰收需分门别类入库。',20,jsonb_build_array(jsonb_build_object('type','rare_item','name','朱果种子','weight',50,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',5,'max_amount',15)),25,60),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'蜂王浆采集','灵蜂蜂王浆是极品炼丹辅料——采集需轻身术接近蜂巢。',15,jsonb_build_array(jsonb_build_object('type','rare_item','name','灵茶叶','weight',70,'min_count',2,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',5,'max_amount',15)),25,55),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'告示牌更新','谷口告示牌每月更新禁令——上月禁止踩聚灵草本月追加禁摘灵芝。',10,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',100,'min_amount',5,'max_amount',12)),25,60),
((SELECT id FROM xt_map_node WHERE name='灵药谷'),'以药换灵石','灵药谷以药换灵石——交出药材换灵石，比率比坊市低但急用。',18,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',80,'min_amount',15,'max_amount',50),jsonb_build_object('type','rare_item','name','千年灵芝孢子','weight',20,'min_count',1,'max_count',1)),25,55);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='须弥山'),'扫地修行','扫三千六百级台阶——扫到三千级会顿悟人生然后发现还有六百级。',45,jsonb_build_array(jsonb_build_object('type','rare_item','name','舍利子','weight',50,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',30,'max_amount',80)),60,30),
