((SELECT id FROM xt_map_node WHERE name='须弥山'),'降魔杵开光','新降魔杵需高僧开光——但高僧要念经四十九天你能先拿一把。',40,jsonb_build_array(jsonb_build_object('type','equipment','name','金刚杵','weight',100,'template_id',(SELECT id FROM xt_equipment_template WHERE name='金刚杵'))),60,25),
