((SELECT id FROM xt_map_node WHERE name='须弥山'),'舍利供养护送','寺中舍利子供奉给其他寺庙——需护送。别打开盒子——里面发光正常。',60,jsonb_build_array(jsonb_build_object('type','rare_item','name','舍利子','weight',60,'min_count',2,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',30,'max_amount',60)),60,20),
((SELECT id FROM xt_map_node WHERE name='须弥山'),'佛前念珠计数','高僧让数念珠——每颗一段经文。数到中途忘了——重新开始。',20,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',100,'min_amount',15,'max_amount',30)),60,30),
((SELECT id FROM xt_map_node WHERE name='须弥山'),'素斋帮厨','须弥山素斋宴——需帮厨切菜摆盘。秘诀：千年灵芝熬汤底一勺就鲜。',25,jsonb_build_array(jsonb_build_object('type','rare_item','name','千年灵芝','weight',60,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',10,'max_amount',25)),60,30),
((SELECT id FROM xt_map_node WHERE name='须弥山'),'菩提叶收集','菩提树千年落叶一次——每片含佛性可换菩提子。',35,jsonb_build_array(jsonb_build_object('type','rare_item','name','菩提子','weight',70,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',10,'max_amount',30)),60,25);
