((SELECT id FROM xt_map_node WHERE name='天机阁'),'星象观测','星象台需夜观天象记录群星轨迹——一颗星三十个字今晚三百颗。',45,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',50,'max_amount',150),jsonb_build_object('type','rare_item','name','悟道丹','weight',40,'min_count',1,'max_count',2)),80,30),
((SELECT id FROM xt_map_node WHERE name='天机阁'),'情报解码','截获魔界暗号情报——需打坐冥想解码。坐三天想到解法——发现是错的。',60,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',50,'max_amount',120),jsonb_build_object('type','rare_item','name','天道碎片','weight',40,'min_count',1,'max_count',2)),85,25),
((SELECT id FROM xt_map_node WHERE name='天机阁'),'古籍修复','上古古籍残页——需以灵气感应填补缺失内容。填对发光填错发黑。',40,jsonb_build_array(jsonb_build_object('type','rare_item','name','悟道丹','weight',50,'min_count',1,'max_count',1),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',30,'max_amount',80)),80,30),
