((SELECT id FROM xt_map_node WHERE name='天机阁'),'历法校准','每百年校准一次历法——最耗时环节：等云散了星辰出来。',120,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',80,'max_amount',200),jsonb_build_object('type','rare_item','name','悟道丹','weight',50,'min_count',1,'max_count',3)),85,25),
((SELECT id FROM xt_map_node WHERE name='天机阁'),'秘境坐标测算','怀疑九天玄刹附近有新秘境入口——需测算坐标。误差三十里。',75,jsonb_build_array(jsonb_build_object('type','rare_item','name','混沌元晶','weight',50,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',50,'max_amount',150)),85,20),
((SELECT id FROM xt_map_node WHERE name='天机阁'),'试炼丹测试','某长老炼出让悟性翻倍的丹——需修士勇敢试吃。副作用暂不知道。',25,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',70,'min_amount',30,'max_amount',100),jsonb_build_object('type','rare_item','name','悟道丹','weight',30,'min_count',1,'max_count',2)),80,30),
((SELECT id FROM xt_map_node WHERE name='天机阁'),'访客登记','月均三千散修来访——需在门口登记。最奇怪访客：声称来自未来的自己——"我是来告诉你别接这任务的。"',15,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',100,'min_amount',20,'max_amount',50)),80,35),
((SELECT id FROM xt_map_node WHERE name='天机阁'),'妖兽驱赶','天机阁高悬云端——偶有妖兽撞到大阵需驱赶。别真打死砸到天阙城赔不起。',30,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',30,'max_amount',100),jsonb_build_object('type','equipment','name','星辰戒','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='星辰戒'))),80,25);
