((SELECT id FROM xt_map_node WHERE name='青云山外门'),'外门巡逻','外门长老安排巡逻确保没妖兽闯入——大部分时间只是散步。',10,jsonb_build_array(jsonb_build_object('type','rare_item','name','凝气丹','weight',60,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',3,'max_amount',8)),5,70),
((SELECT id FROM xt_map_node WHERE name='青云山外门'),'妖兽清剿','附近几只妖狼需清理——适合想证明自己的新手。失败会得到：道友要不先练轻身术？',15,jsonb_build_array(jsonb_build_object('type','rare_item','name','筑基丹','weight',60,'min_count',1,'max_count',1),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',5,'max_amount',12)),8,60),
