((SELECT id FROM xt_map_node WHERE name='枯骨林入口'),'破旧法器回收','商人专收枯骨林破旧法器——破是破回头翻新还能卖。',30,jsonb_build_array(jsonb_build_object('type','rare_item','name','星辰砂','weight',50,'min_count',1,'max_count',5),jsonb_build_object('type','equipment','name','粗布道袍','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='粗布道袍'))),10,45),
((SELECT id FROM xt_map_node WHERE name='枯骨林入口'),'夜巡枯骨林','夜晚亡魂活跃——需夜巡确保不越过林界。带够照明掏出火球术才发现被噬魂鬼包围了。',18,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',10,'max_amount',30),jsonb_build_object('type','rare_item','name','回春丹','weight',50,'min_count',1,'max_count',2)),12,45),
((SELECT id FROM xt_map_node WHERE name='枯骨林入口'),'林标更新','标牌被妖兽撞烂三十个——需重新插标牌。——一个五块灵石走完人已成形。',25,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',80,'min_amount',15,'max_amount',40),jsonb_build_object('type','rare_item','name','玄铁','weight',20,'min_count',1,'max_count',3)),10,45),
((SELECT id FROM xt_map_node WHERE name='枯骨林入口'),'妖兽击退','入口妖兽增多——需去击退几个震慑。',15,jsonb_build_array(jsonb_build_object('type','rare_item','name','火灵石','weight',60,'min_count',1,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',5,'max_amount',15)),10,50),
((SELECT id FROM xt_map_node WHERE name='枯骨林入口'),'散修救援','一队散修遇袭发出求救信号——救出来有谢礼。',20,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',12,'max_amount',30),jsonb_build_object('type','rare_item','name','大还丹','weight',50,'min_count',1,'max_count',2)),12,45),
((SELECT id FROM xt_map_node WHERE name='枯骨林入口'),'磷火采集','枯骨林的磷火是炼丹辅料——装进罐子就值灵石。踩到会烫脚。',22,jsonb_build_array(jsonb_build_object('type','rare_item','name','灵茶叶','weight',70,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',5,'max_amount',12)),10,50);
