((SELECT id FROM xt_map_node WHERE name='仙界遗迹核心'),'混沌巨兽守护','遗迹核心有混沌巨兽守护——需战而胜之。天机阁称百年来没人做到。',300,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',100,'max_amount',500),jsonb_build_object('type','equipment','name','承影剑','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='承影剑'))),100,2),
((SELECT id FROM xt_map_node WHERE name='仙界遗迹核心'),'天劫雷兽巢穴','核心深处有天劫雷兽巢穴——需清剿。建议带涅槃丹多多益善。',240,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',80,'max_amount',400),jsonb_build_object('type','equipment','name','诛仙弓','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='诛仙弓'))),100,3),
((SELECT id FROM xt_map_node WHERE name='仙界遗迹核心'),'修罗王降临','核心偶出现修罗王真身——天机阁悬赏勇士讨伐。十大不可能悬赏之首。',360,jsonb_build_array(jsonb_build_object('type','rare_item','name','九转金丹','weight',50,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',120,'max_amount',500)),100,2),
((SELECT id FROM xt_map_node WHERE name='仙界遗迹核心'),'仙气凝结珠','最高浓度仙气能凝结成珠——需修士在最深处打坐十昼夜。身体会被仙气重塑。',720,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道碎片','weight',70,'min_count',3,'max_count',10),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',100,'max_amount',300)),100,1),
((SELECT id FROM xt_map_node WHERE name='仙界遗迹核心'),'远古石像鬼破译','核心有远古石像鬼雕像——记载着仙界历史需用灵识破译。',180,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',60,'max_amount',300),jsonb_build_object('type','rare_item','name','悟道丹','weight',50,'min_count',1,'max_count',3)),98,3),
((SELECT id FROM xt_map_node WHERE name='仙界遗迹核心'),'仙帝传承试炼','仙帝留下的传承试炼——九关一关比一关难——全部通过据说获仙帝衣钵。',480,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',100,'max_amount',500),jsonb_build_object('type','equipment','name','天机盘','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='天机盘'))),100,2),
((SELECT id FROM xt_map_node WHERE name='仙界遗迹核心'),'九天息壤矿','核心有九天息壤原生矿脉——需去开采。挖一撮重若千钧——多挖几撮储物袋都沉。',120,jsonb_build_array(jsonb_build_object('type','rare_item','name','九天息壤','weight',80,'min_count',2,'max_count',10),jsonb_build_object('type','spirit_stones','name','灵石','weight',20,'min_amount',40,'max_amount',120)),100,3),
((SELECT id FROM xt_map_node WHERE name='仙界遗迹核心'),'终极探索','修真界终极目的地——踏入核心最深区——什么也没有也什么都有——取决于道心。',1440,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道碎片','weight',50,'min_count',5,'max_count',20),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',200,'max_amount',500)),100,1);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'阴间快递','深渊底部存在需人间日用品——带一箱下去交了回来。深渊怪物抢那箱东西因为好奇。',60,jsonb_build_array(jsonb_build_object('type','rare_item','name','虚空结晶','weight',50,'min_count',1,'max_count',5),jsonb_build_object('type','rare_item','name','虚空草','weight',50,'min_count',1,'max_count',3)),55,20),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'冥界神树果实','据说深渊底部冥界神树果实能让活人看前世——但声称看到的其实都是饿的幻觉。',90,jsonb_build_array(jsonb_build_object('type','rare_item','name','神血石','weight',50,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',40,'max_amount',120)),58,15),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'深渊采矿','幽冥铁和魔血石主产地——下去采一筐上来。注意：采矿越深阴气越重呼吸变慢注意回春。',80,jsonb_build_array(jsonb_build_object('type','rare_item','name','幽冥铁','weight',60,'min_count',2,'max_count',8),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',30,'max_amount',100)),55,15),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'吞噬魔追踪','深渊吞噬魔族群迁徙——需人追踪去向标本数量。追踪时如果感觉周围暗了跑——它不是你的对手。',45,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',30,'max_amount',100),jsonb_build_object('type','rare_item','name','魔血石','weight',40,'min_count',1,'max_count',3)),58,15),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'星辰守护者研究','深渊底部偶有星辰守护者降临——需靠近观察记录行为不被发现。',60,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',40,'max_amount',150),jsonb_build_object('type','equipment','name','星辰戒','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='星辰戒'))),58,10),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'魔界之主封印探查','传说深渊底部镇压魔界之主分身——需去探查看封印有无松动。看就好别看太久。',90,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',50,'max_amount',200),jsonb_build_object('type','rare_item','name','神血石','weight',50,'min_count',1,'max_count',5)),60,10),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'阴气淬炼','深渊阴气浓郁能淬炼冰属修士——打坐三天比外面快十倍但须每半时辰用回春术。',120,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',40,'max_amount',120),jsonb_build_object('type','rare_item','name','破魔丹','weight',50,'min_count',1,'max_count',2)),55,10),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'冥界传送门守门','深渊底部有古老冥界传送门——虽不常开但需人看守确保无人擅闯。',90,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',40,'max_amount',150),jsonb_build_object('type','beast_egg','name','灵兽卵','weight',40)),55,10),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'幽灵花种植','有人想在最深处试种幽灵花——需助手帮忙挖坑注冥界的阴气浇灌。',120,jsonb_build_array(jsonb_build_object('type','rare_item','name','九幽花','weight',60,'min_count',1,'max_count',2),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',30,'max_amount',100)),55,10),
((SELECT id FROM xt_map_node WHERE name='幽冥深渊'),'深渊地图更新','天机阁需深井最新详细地图——需一步一脚印走遍深渊所有角落。',180,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',60,'max_amount',250),jsonb_build_object('type','rare_item','name','天道花瓣','weight',40,'min_count',1,'max_count',3)),58,8);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='远古神墓'),'解谜大师','上古谜题——解开获神祇祝福。失传文字笔仙可每天翻译十个字——马拉松解谜最慢悬赏。',180,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道碎片','weight',50,'min_count',1,'max_count',5),jsonb_build_object('type','rare_item','name','神血石','weight',50,'min_count',1,'max_count',5)),75,12),
((SELECT id FROM xt_map_node WHERE name='远古神墓'),'墓穴探索','古墓深处有未勘探墓室——去探索并绘制地图。入口刻擅入者死下面小字：我家就是被擅入者灭门的。',120,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',50,'max_amount',200),jsonb_build_object('type','rare_item','name','混沌元晶','weight',50,'min_count',1,'max_count',3)),78,10),
((SELECT id FROM xt_map_node WHERE name='远古神墓'),'魔界之主守卫','神墓深处魔界之主在此守卫——需讨伐。不要问为什么他在神墓——没人知道。',180,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',80,'max_amount',400),jsonb_build_object('type','equipment','name','血魂刀','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='血魂刀'))),82,8),
((SELECT id FROM xt_map_node WHERE name='远古神墓'),'天道化身交流','神墓最底层据说有天道化身的投影——去和它交流。问它宇宙终极答案——它说三答案是错。',240,jsonb_build_array(jsonb_build_object('type','rare_item','name','悟道丹','weight',60,'min_count',1,'max_count',3),jsonb_build_object('type','rare_item','name','天道花瓣','weight',40,'min_count',1,'max_count',3)),80,8),
