((SELECT id FROM xt_map_node WHERE name='远古神墓'),'混沌之眼监视','天机阁发现神墓深处有一只混沌之眼——需人远距离观察不打扰。',60,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',40,'max_amount',150),jsonb_build_object('type','rare_item','name','混沌元晶','weight',40,'min_count',1,'max_count',2)),80,8),
((SELECT id FROM xt_map_node WHERE name='远古神墓'),'万剑剑灵追踪','神墓附近偶出现万剑剑灵——需追踪其路径记录。靠近会听到万千剑鸣——是警告也是邀请。',75,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',50,'max_amount',200),jsonb_build_object('type','equipment','name','裂天剑','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='裂天剑'))),78,8),
((SELECT id FROM xt_map_node WHERE name='远古神墓'),'古墓守陵仪式','有朝圣者想入墓行古礼——需修士陪同并主持仪式。仪式内容：拜三次上香读一篇祭文。',60,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',30,'max_amount',100),jsonb_build_object('type','rare_item','name','舍利子','weight',40,'min_count',1,'max_count',3)),75,12),
((SELECT id FROM xt_map_node WHERE name='远古神墓'),'神力残留采集','神墓中残留上神神力——用特制容器收集。一滴神力可炼极品补神丹。',120,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道碎片','weight',60,'min_count',1,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',40,'max_amount',200)),80,5),
((SELECT id FROM xt_map_node WHERE name='远古神墓'),'封神石碑拓印','神墓入口封神石碑刻满不知名文字——需全部拓印回来给天机阁。字多到让你怀疑人生——但一字三灵石。',180,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',70,'min_amount',50,'max_amount',250),jsonb_build_object('type','rare_item','name','神血石','weight',30,'min_count',1,'max_count',3)),75,8);
