((SELECT id FROM xt_map_node WHERE name='天道之路'),'万剑剑灵决斗','路上偶遇万剑剑灵——愿意公正对决——赢了获得剑道传承。',120,jsonb_build_array(jsonb_build_object('type','equipment','name','承影剑','weight',60,'template_id',(SELECT id FROM xt_equipment_template WHERE name='承影剑')),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',60,'max_amount',200)),95,3),
((SELECT id FROM xt_map_node WHERE name='天道之路'),'墓碑祭祀','有两旁无数修士墓碑——需逐一扫墓点香——每扫一座都有一小段灵气回馈。',90,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',50,'max_amount',150),jsonb_build_object('type','rare_item','name','天道花瓣','weight',40,'min_count',1,'max_count',3)),95,5),
((SELECT id FROM xt_map_node WHERE name='天道之路'),'飞升之光追逐','有人声称在天道之路上空看到飞升之光——需人去追查。跑十里光散了——但看到本身值一件装备。',60,jsonb_build_array(jsonb_build_object('type','equipment','name','苍穹弓','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='苍穹弓')),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',30,'max_amount',100)),95,5),
((SELECT id FROM xt_map_node WHERE name='天道之路'),'上古龙神观测','天道之路上空偶尔上古龙神飞过——需观测并记录飞行路线。',75,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',40,'max_amount',200),jsonb_build_object('type','rare_item','name','龙血草','weight',50,'min_count',1,'max_count',3)),95,3),
((SELECT id FROM xt_map_node WHERE name='天道之路'),'天劫余烬收集','天道之路经历天劫后地面残留余烬——收集可炼破劫丹。',45,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道碎片','weight',70,'min_count',1,'max_count',3),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',30,'max_amount',100)),95,5),
((SELECT id FROM xt_map_node WHERE name='天道之路'),'飞升失败遗物','有飞升失败修士遗留的法器在路上——需去找回。也算给这位修士留个身后名。',120,jsonb_build_array(jsonb_build_object('type','equipment','name','雷劫铠甲','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='雷劫铠甲')),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',50,'max_amount',200)),95,3),
((SELECT id FROM xt_map_node WHERE name='天道之路'),'终途参禅','在飞升台前打坐参悟——据说能看到自己的未来——也可能什么都没看到——但你离天道最近。',480,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道花瓣','weight',50,'min_count',1,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',80,'max_amount',300)),100,2);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'时空猎人','虚空裂缝出现虚空领主——天机阁悬赏最强修士击杀。十大不可能悬赏。',240,jsonb_build_array(jsonb_build_object('type','rare_item','name','混沌元晶','weight',50,'min_count',1,'max_count',10),jsonb_build_object('type','rare_item','name','九转金丹','weight',50,'min_count',1,'max_count',3)),85,5),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'虚空结晶采集','裂缝喷涌混沌气——在裂缝边缘采集虚空结晶。注意：虚空结晶有时会连同采集手一起短暂传送。',60,jsonb_build_array(jsonb_build_object('type','rare_item','name','虚空结晶','weight',70,'min_count',3,'max_count',12),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',30,'max_amount',100)),85,5),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'魔界之主征讨','裂缝深处出现魔界之主——需勇士征讨。多数修士去了就再没回来——报酬高到离谱因没人领。',300,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',100,'max_amount',500),jsonb_build_object('type','equipment','name','破军锤','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='破军锤'))),90,3),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'万剑剑灵踪迹','裂缝中偶见万剑剑灵穿梭——需记录其出现规律。',75,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',50,'max_amount',200),jsonb_build_object('type','rare_item','name','天道碎片','weight',50,'min_count',1,'max_count',3)),85,5),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'混沌修炼','疯子修士最爱在裂缝边修炼——一天抵十年——修完是人是妖不在统计范围。',180,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',60,'max_amount',200),jsonb_build_object('type','rare_item','name','混沌元晶','weight',40,'min_count',1,'max_count',3)),90,3),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'飞升失败者讨伐','裂缝周围有飞升失败者徘徊——需去讨伐。每位失败者都曾是即将飞升的大能——实力仍在。',240,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',80,'max_amount',400),jsonb_build_object('type','equipment','name','裂天剑','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='裂天剑'))),90,3),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'时空裂缝测绘','天机阁需人绘制虚空裂缝变动图——裂缝每时变化需用高灵神识感应边缘。',120,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',60,'max_amount',250),jsonb_build_object('type','rare_item','name','虚空结晶','weight',40,'min_count',1,'max_count',5)),85,3),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'虚空领主目击记录','天机阁需人记录虚空领主每天出没时间——蹲点蹲十二时辰天天如此。',150,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',50,'max_amount',250),jsonb_build_object('type','beast_egg','name','灵兽卵','weight',40)),85,3),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'混沌之气收集瓶','裂缝逸散的混沌之气——需用特制收集瓶。瓶子贵但要收集满一瓶十天',300,jsonb_build_array(jsonb_build_object('type','rare_item','name','混沌元晶','weight',70,'min_count',1,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',40,'max_amount',200)),90,3),
((SELECT id FROM xt_map_node WHERE name='虚空裂缝'),'虚空召唤','裂缝偶尔传出虚无之音——说是召唤也说是警告——需人去调研并回报。',90,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',40,'max_amount',150),jsonb_build_object('type','rare_item','name','天道碎片','weight',50,'min_count',1,'max_count',3)),85,5);
INSERT INTO xt_bounty (map_id, name, description, duration_minutes, rewards, require_level, event_weight) VALUES
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'本源探索','修真界最大悬赏——追寻混沌之源。赏金可买整座天阙城——已挂六千年无人领。',8760,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道碎片','weight',50,'min_count',1,'max_count',20),jsonb_build_object('type','rare_item','name','混沌元晶','weight',50,'min_count',1,'max_count',20)),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'天道碎片终极收集','混沌之源的天道碎片最为纯洁——找到并带回。一年回一次——值得等。',2160,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道碎片','weight',70,'min_count',1,'max_count',10),jsonb_build_object('type','spirit_stones','name','灵石','weight',30,'min_amount',100,'max_amount',300)),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'上古龙神对战','混沌之源上空盘踞上古龙神真身——天机阁悬赏最强修士挑战。',480,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',200,'max_amount',800),jsonb_build_object('type','equipment','name','承影剑','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='承影剑'))),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'万剑剑灵集合','混沌之源无数万剑剑灵——需去直面而不退——立于剑阵而不倒的奖励无与伦。',360,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',150,'max_amount',600),jsonb_build_object('type','equipment','name','裂天剑','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='裂天剑'))),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'飞升失败者解救','混沌之源汇聚大量飞升失败者——需去解救他们的道心。对话——不是打——理念之争。',720,jsonb_build_array(jsonb_build_object('type','rare_item','name','悟道丹','weight',60,'min_count',1,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',80,'max_amount',400)),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'混沌巨兽防御','混沌巨兽守卫混沌之源入口——需击退不能杀——杀掉混沌失衡——击退就好。',600,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',100,'max_amount',500),jsonb_build_object('type','equipment','name','混沌护符','weight',50,'template_id',(SELECT id FROM xt_equipment_template WHERE name='混沌护符'))),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'道之本源采气','混沌之源最纯道之本源——能用特制容器采集——带回就是无价。容器只能用一次——用完能换一枚天道碎片。',1440,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道花瓣','weight',80,'min_count',3,'max_count',15),jsonb_build_object('type','spirit_stones','name','灵石','weight',20,'min_amount',60,'max_amount',200)),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'混沌花鉴定','混沌之源某种花据说可生吃——吃了直接突破——需人去鉴定。上一个人吃了消失了——证明可能有效也可能他跑了。',240,jsonb_build_array(jsonb_build_object('type','rare_item','name','混沌元晶','weight',60,'min_count',1,'max_count',5),jsonb_build_object('type','spirit_stones','name','灵石','weight',40,'min_amount',50,'max_amount',300)),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'终极冥想','混沌之源静坐冥想——吸收混沌初开之气——最接近天道的地方。',1080,jsonb_build_array(jsonb_build_object('type','spirit_stones','name','灵石','weight',60,'min_amount',120,'max_amount',500),jsonb_build_object('type','rare_item','name','天道花瓣','weight',40,'min_count',1,'max_count',5)),100,1),
((SELECT id FROM xt_map_node WHERE name='混沌之源'),'归元','修真界最终归处——混沌之源——打坐之后可能回来——可能不回来——但无论怎样——你已到终途。',52560,jsonb_build_array(jsonb_build_object('type','rare_item','name','天道碎片','weight',50,'min_count',5,'max_count',50),jsonb_build_object('type','spirit_stones','name','灵石','weight',50,'min_amount',500,'max_amount',2000)),100,1);
